  ('aboriginal-c5fb3965-moex-00201', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '下列各組「 」內的字，何者色系差異最大？', '["獲得「青」睞／紅男「綠」女", "赤膽「丹」心／「絳」帳授徒", "皮膚「黝」亮／「烏」雲密布", "「皓」首窮經／好丹非「素」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00202', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「佛洛依德曾給自己推崇的作家施尼支勒寫信，認為他用美麗的文學手法，實現了自己多年來在『下 意識』的茫茫海洋裡探尋的目標，是現代心理學在詩壇上的先驅。有趣的是，這兩位□□已久的名家 都時常出入『咖啡中心』，卻從未在那裡謀面過。」上文空缺處，最適合填入的是：', '["撥交", "面交", "邦交", "神交"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00203', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '《禮記》：「君子之於學也，藏焉，脩焉，息焉，游焉。」 下列成語，何者與上文旨意最接近？', '["牛角掛書", "徵奇涉怪", "一曝十寒", "循常習故"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00204', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「梁紅玉是南宋名將韓世忠之妻，曾助夫擊鼓作戰，打退金兵；如此女子，堪稱□□□□。」下列選 項的成語，何者適合填入空格中？', '["一顧傾城", "舉案齊眉", "鬚髯如戟", "巾幗鬚眉"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00205', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '下列「」中成語應用，何者完全正確？', '["小明考試作弊，居然沒有被發現，真是「天助自助」啊", "老張是「一諾千金」的人，事情交給他，你就可以放心了", "他「目不見睫」看著我，眼神傳送強烈電波，我想他是愛上我了", "他一心一意要到巴黎學畫，效法「邯鄲學步」，在藝術之都接受西方文化洗禮"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00206', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '下列「」中的成語，使用正確的是：', '["老陳庭訓甚嚴，訓練孩子要「名韁利鎖」，留意於名實相符", "李老師任教數十年，始終「師心自用」，一本初衷的關懷學生", "詐騙集團嫌疑人果然「凶終隙末」，最終還是露出破綻，被移送法辦", "老張生性淡泊名利，常抱「富貴浮雲」的態度，因此政治生涯始終清廉自持"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00207', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '下列文句，何者沒有語病？', '["黑色在五行中屬火，廚房屬水，在風水上相剋，因此在裝潢時不介意使用黑色", "立法院尚未完成消毒，呼籲相關部會的訪客，一定要務必注意，落實防疫工作", "人氣美食名店名不虛傳，真可謂「吃一口，欲罷不能；來一次，終生成主顧」", "我們致力提供優質服務，以配合您的需求：會籍級別愈高，所享的服務就愈超越"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL)
